print(f"{(horas1 := float(input('Insira a quantidade de horas aula dadas pelo 1o professor: '))) and ''}{(valor1 := float(input('Insira o valor por hora recebido pelo 1o professor: '))) and ''}{(horas2 := float(input('Insira a quantidade de horas aula dadas pelo 2o professor: '))) and ''}{(valor2 := float(input('Insira o valor por hora recebido pelo 2o professor: '))) and ''}{('O 1o professor tem salário total maior.' if horas1 * valor1 > horas2 * valor2 else 'O 2o professor tem salário total maior.')}")
